proof_block:
// Surface the destructured tuple components as named locals so z3 has
// explicit ground terms (ok1, ne1, ok2, ne2) to trigger on; the original
// ensures hides them behind `let (ok, Ghost(net_event)) = rc` patterns
// that produce disjoint triggers across the two runs.
let ok1: bool = r1.0;
let ok2: bool = r2.0;
let ne1: Option<NetEvent> = (r1.1)@;
let ne2: Option<NetEvent> = (r2.1)@;

// The `my_end_point()` equality between post1 and post2 IS derivable —
// each ensures pins post_i.my_end_point() to pre_netc.my_end_point(), so
// transitivity closes the gap.  This is the only NetClient projection the
// ensures forces equal across the two runs.
assert(post1_netc.my_end_point() == pre_netc.my_end_point());
assert(post2_netc.my_end_point() == pre_netc.my_end_point());
assert(post1_netc.my_end_point() == post2_netc.my_end_point());

// Re-trigger the ok <==> netc.ok() conjuncts so z3 has the per-run
// ground facts available without re-expanding the structured ensures.
assert(post1_netc.ok() <==> ok1);
assert(post2_netc.ok() <==> ok2);

// In the both-ok branch the ensures pins down per-run history extensions
// (over the OPAQUE `history()` spec fn — NOT the `history@` field that
// `NetClient::view` projects) and the per-event reflects/marshalable
// facts.  We surface every such derivable equality so the failure mode is
// "irreducibly under-determined ensures", not a quantifier-trigger gap.
if ok1 && ok2 {
    assert(ne1 is Some);
    assert(ne2 is Some);
    assert(post1_netc.history() == pre_netc.history() + seq![ne1.unwrap()]);
    assert(post2_netc.history() == pre_netc.history() + seq![ne2.unwrap()]);

    assert(send_log_entry_reflects_packet(ne1.unwrap(), &cpacket));
    assert(send_log_entry_reflects_packet(ne2.unwrap(), &cpacket));
    assert(ne1.unwrap() is Send);
    assert(ne2.unwrap() is Send);

    // send_log_entry_reflects_packet pins
    //   cpacket@ == abstractify_net_packet_to_sht_packet(event.arrow_Send_s())
    // for each event, so both abstractified projections coincide.
    assert(cpacket@ == abstractify_net_packet_to_sht_packet(ne1.unwrap().arrow_Send_s()));
    assert(cpacket@ == abstractify_net_packet_to_sht_packet(ne2.unwrap().arrow_Send_s()));
    assert(abstractify_net_packet_to_sht_packet(ne1.unwrap().arrow_Send_s())
        == abstractify_net_packet_to_sht_packet(ne2.unwrap().arrow_Send_s()));

    assert(is_marshalable_data(ne1.unwrap()));
    assert(is_marshalable_data(ne2.unwrap()));
}
